$baseUrl = "http://localhost:5000/api"
$email = "testuser_ver_" + (Get-Date -Format "yyyyMMddHHmmss") + "@example.com"
$password = "password123"

Write-Host "--- Verifying Backend API ---" -ForegroundColor Cyan

# 1. Register User
$registerBody = @{
    fullName = "Test User"
    email    = $email
    password = $password
} | ConvertTo-Json

try {
    Write-Host "1. Registering User ($email)..." -NoNewline
    $registerResponse = Invoke-RestMethod -Uri "$baseUrl/auth/register" -Method Post -Body $registerBody -ContentType "application/json" -ErrorAction Stop
    if ($registerResponse.success) {
        Write-Host " [OK]" -ForegroundColor Green
    } else {
        Write-Host " [FAILED]" -ForegroundColor Red
        Write-Host $registerResponse
        exit 1
    }
} catch {
    Write-Host " [FAILED]" -ForegroundColor Red
    Write-Host $_.Exception.Response
    # Continue to login just in case user exists
}

# 2. Login User
$loginBody = @{
    email    = $email
    password = $password
} | ConvertTo-Json

try {
    Write-Host "2. Logging In..." -NoNewline
    $loginResponse = Invoke-RestMethod -Uri "$baseUrl/auth/login" -Method Post -Body $loginBody -ContentType "application/json" -ErrorAction Stop
    
    if ($loginResponse.success) {
        $token = $loginResponse.data.token
        Write-Host " [OK]" -ForegroundColor Green
        # Write-Host "Token: $token"
    } else {
        Write-Host " [FAILED]" -ForegroundColor Red
        exit 1
    }
} catch {
    Write-Host " [FAILED]" -ForegroundColor Red
    Write-Host $_.Exception.Message
    exit 1
}

# Headers for authenticated requests
$headers = @{
    Authorization = "Bearer $token"
}

# 3. Get User Profile
try {
    Write-Host "3. getting Profile..." -NoNewline
    $meResponse = Invoke-RestMethod -Uri "$baseUrl/auth/me" -Method Get -Headers $headers -ErrorAction Stop
    if ($meResponse.success) {
        Write-Host " [OK] - Hello $($meResponse.data.user.fullName)" -ForegroundColor Green
    } else {
        Write-Host " [FAILED]" -ForegroundColor Red
    }
} catch {
    Write-Host " [FAILED]" -ForegroundColor Red
    Write-Host $_.Exception.Message
}

# 4. Create Expense
$expenseBody = @{
    category = "FOOD"
    type     = "Lunch"
    amount   = 150
    date     = (Get-Date).ToString("yyyy-MM-dd")
    notes    = "Test Expense"
} | ConvertTo-Json

try {
    Write-Host "4. Creating Expense..." -NoNewline
    $expenseResponse = Invoke-RestMethod -Uri "$baseUrl/expenses" -Method Post -Body $expenseBody -ContentType "application/json" -Headers $headers -ErrorAction Stop
    if ($expenseResponse.success) {
        Write-Host " [OK]" -ForegroundColor Green
    } else {
        Write-Host " [FAILED]" -ForegroundColor Red
        Write-Host $expenseResponse
    }
} catch {
    Write-Host " [FAILED]" -ForegroundColor Red
    Write-Host $_.Exception.Message
}

# 5. List Expenses
try {
    Write-Host "5. Listing Expenses..." -NoNewline
    $listResponse = Invoke-RestMethod -Uri "$baseUrl/expenses" -Method Get -Headers $headers -ErrorAction Stop
    if ($listResponse.success) {
        $count = $listResponse.data.count
        Write-Host " [OK] - Found $count expenses" -ForegroundColor Green
    } else {
        Write-Host " [FAILED]" -ForegroundColor Red
    }
} catch {
    Write-Host " [FAILED]" -ForegroundColor Red
    Write-Host $_.Exception.Message
}

Write-Host "--- Backend Verification Complete ---" -ForegroundColor Cyan
